use std::borrow::Cow;

fn maybe_escape(input: &str) -> Cow<'_, str> {
    if input.contains('<') {
        Cow::Owned(input.replace('<', "&lt;"))
    } else {
        Cow::Borrowed(input)   // no allocation
    }
}

let a = maybe_escape("hello");      // Borrowed
let b = maybe_escape("a<b");        // Owned

